const body = $json.body ?? $json;
const agent = (body.agent || 'echo').toLowerCase();
const action = (body.action || 'manifest').toLowerCase();
const sessionId = body.session_id || `session_${Date.now()}`;
const userId = body.user_id || 'connor';
const map = {
  echo: { chat: 'echo_chat_chunks', docs: 'echo_docs', notes: 'echo_obsidian', namespace: 'echo' },
  skippy: { chat: 'skippy_chat_chunks', docs: 'skippy_home_docs', notes: 'skippy_obsidian', namespace: 'skippy' },
};
const selected = map[agent] || map.echo;
return [{
  json: {
    action,
    agent,
    user_id: userId,
    session_id: sessionId,
    query: body.query || '',
    messages: body.messages || [],
    source_type: body.source_type || 'chat',
    source_path: body.source_path || null,
    tags: body.tags || [],
    collection_chat: selected.chat,
    collection_docs: selected.docs,
    collection_notes: selected.notes,
    memory_namespace: selected.namespace,
  }
}];

const facts = $('Fetch Structured Facts').all().map(i => i.json);
const rag = $json.result?.points || $json.result || [];
return [{
  json: {
    action: 'retrieve',
    agent: $('Normalize Payload').item.json.agent,
    session_id: $('Normalize Payload').item.json.session_id,
    memory_names: {
      namespace: $('Normalize Payload').item.json.memory_namespace,
      chat_collection: $('Normalize Payload').item.json.collection_chat,
      docs_collection: $('Normalize Payload').item.json.collection_docs,
      notes_collection: $('Normalize Payload').item.json.collection_notes
    },
    structured_facts: facts,
    rag_hits: rag,
    retrieval_bundle: {
      structured_fact_count: facts.length,
      rag_hit_count: Array.isArray(rag) ? rag.length : 0
    }
  }
}];

const x = $json;
return [{
  json: {
    action: 'manifest',
    agent: x.agent,
    session_id: x.session_id,
    memory_namespace: x.memory_namespace,
    qdrant: {
      chat_collection: x.collection_chat,
      docs_collection: x.collection_docs,
      notes_collection: x.collection_notes
    },
    exports: [
      `agent.${x.agent}.identity.md`,
      `agent.${x.agent}.system-prompt.md`,
      `agent.${x.agent}.retrieval-prompt.md`,
      `${x.agent}.memory-facts.jsonl`,
      `${x.agent}.memory-events.jsonl`,
      `${x.agent}.session-summaries.jsonl`,
      `${x.agent}.review-queue.jsonl`,
      `${x.agent}.qdrant-collections.json`,
      `${x.agent}.obsidian-export.md`
    ]
  }
}];

const messages = Array.isArray($json.messages) ? $json.messages : [];
const transcript = messages.map((m, idx) => {
  const role = m.role || 'user';
  const content = typeof m.content === 'string' ? m.content : JSON.stringify(m.content || {});
  return `${idx + 1}. [${role}] ${content}`;
}).join('\n');
return [{ json: { ...$json, transcript_text: transcript || '[no transcript provided]' } }];

const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  parsed = {
    title: 'parse_failed',
    summary_short: String(raw).slice(0, 240),
    summary_long: String(raw),
    facts: [],
    events: [],
    tasks: [],
    tags: ['parse_failed']
  };
}
return [{ json: { ...$('Prepare Transcript').item.json, extracted: parsed } }];

return [{
  json: {
    action: 'ingest',
    agent: $('Parse Summary JSON').item.json.agent,
    session_id: $('Parse Summary JSON').item.json.session_id,
    stored: {
      session_summary: true,
      review_queue: true,
      qdrant: true
    },
    memory_names: {
      namespace: $('Parse Summary JSON').item.json.memory_namespace,
      chat_collection: $('Parse Summary JSON').item.json.collection_chat,
      docs_collection: $('Parse Summary JSON').item.json.collection_docs,
      notes_collection: $('Parse Summary JSON').item.json.collection_notes
    },
    extracted_preview: {
      title: $('Parse Summary JSON').item.json.extracted.title,
      summary_short: $('Parse Summary JSON').item.json.extracted.summary_short,
      fact_count: ($('Parse Summary JSON').item.json.extracted.facts || []).length,
      event_count: ($('Parse Summary JSON').item.json.extracted.events || []).length,
      task_count: ($('Parse Summary JSON').item.json.extracted.tasks || []).length
    }
  }
}];
